const codes = {"Java": "<span class=\"kw\">interface</span> <span class=\"cl\">DataService</span> {\n  <span class=\"cl\">String</span> <span class=\"fn\">getData</span>(<span class=\"cl\">String</span> <span class=\"dc\">id</span>);\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">Real</span> <span class=\"kw\">implements</span> <span class=\"cl\">DataService</span> {\n  <span class=\"kw\">public</span> <span class=\"cl\">String</span> <span class=\"fn\">getData</span>(<span class=\"cl\">String</span> <span class=\"dc\">id</span>) {\n    <span class=\"kw\">return</span> <span class=\"st\">\"data-\"</span> + <span class=\"dc\">id</span>;\n  }\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">CacheProxy</span> <span class=\"kw\">implements</span> <span class=\"cl\">DataService</span> {\n  <span class=\"kw\">private final</span> <span class=\"cl\">DataService</span> <span class=\"dc\">svc</span>;\n  <span class=\"kw\">private final</span> <span class=\"cl\">Map</span>&lt;<span class=\"cl\">String</span>,<span class=\"cl\">String</span>&gt; <span class=\"dc\">cache</span> = <span class=\"kw\">new</span> <span class=\"cl\">HashMap</span>&lt;&gt;();\n\n  <span class=\"fn\">CacheProxy</span>(<span class=\"cl\">DataService</span> <span class=\"dc\">s</span>) { <span class=\"dc\">svc</span> = <span class=\"dc\">s</span>; }\n\n  <span class=\"kw\">public</span> <span class=\"cl\">String</span> <span class=\"fn\">getData</span>(<span class=\"cl\">String</span> <span class=\"dc\">id</span>) {\n    <span class=\"kw\">return</span> <span class=\"dc\">cache</span>.<span class=\"fn\">computeIfAbsent</span>(<span class=\"dc\">id</span>, <span class=\"dc\">svc</span>::<span class=\"fn\">getData</span>);\n  }\n}", "CSharp": "<span class=\"kw\">public interface</span> <span class=\"cl\">IData</span> {\n  <span class=\"kw\">string</span> <span class=\"fn\">Get</span>(<span class=\"kw\">string</span> <span class=\"dc\">id</span>);\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">Real</span> : <span class=\"cl\">IData</span> {\n  <span class=\"kw\">public string</span> <span class=\"fn\">Get</span>(<span class=\"kw\">string</span> <span class=\"dc\">id</span>) =&gt; <span class=\"st\">\"data-\"</span> + <span class=\"dc\">id</span>;\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">CacheProxy</span>(<span class=\"cl\">IData</span> <span class=\"dc\">svc</span>) : <span class=\"cl\">IData</span> {\n  <span class=\"kw\">readonly</span> <span class=\"cl\">Dictionary</span>&lt;<span class=\"kw\">string</span>,<span class=\"kw\">string</span>&gt; <span class=\"dc\">_c</span> = <span class=\"kw\">new</span>();\n\n  <span class=\"kw\">public string</span> <span class=\"fn\">Get</span>(<span class=\"kw\">string</span> <span class=\"dc\">id</span>) {\n    <span class=\"kw\">if</span> (!<span class=\"dc\">_c</span>.<span class=\"fn\">ContainsKey</span>(<span class=\"dc\">id</span>))\n      <span class=\"dc\">_c</span>[<span class=\"dc\">id</span>] = <span class=\"dc\">svc</span>.<span class=\"fn\">Get</span>(<span class=\"dc\">id</span>);\n    <span class=\"kw\">return</span> <span class=\"dc\">_c</span>[<span class=\"dc\">id</span>];\n  }\n}", "Python": "<span class=\"kw\">class</span> <span class=\"cl\">CacheProxy</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"dc\">self</span>, <span class=\"dc\">svc</span>):\n    <span class=\"dc\">self.svc</span>, <span class=\"dc\">self._c</span> = <span class=\"dc\">svc</span>, {}\n\n  <span class=\"kw\">def</span> <span class=\"fn\">get_data</span>(<span class=\"dc\">self</span>, <span class=\"dc\">id</span>):\n    <span class=\"kw\">if</span> <span class=\"dc\">id</span> <span class=\"kw\">not in</span> <span class=\"dc\">self._c</span>:\n      <span class=\"dc\">self._c</span>[<span class=\"dc\">id</span>] = <span class=\"dc\">self.svc</span>.<span class=\"fn\">get_data</span>(<span class=\"dc\">id</span>)\n    <span class=\"kw\">return</span> <span class=\"dc\">self._c</span>[<span class=\"dc\">id</span>]", "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">CacheProxy</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">initialize</span>(<span class=\"dc\">svc</span>) = (<span class=\"dc\">@svc</span> = <span class=\"dc\">svc</span>; <span class=\"dc\">@c</span> = {})\n\n  <span class=\"kw\">def</span> <span class=\"fn\">get_data</span>(<span class=\"dc\">id</span>)\n    <span class=\"dc\">@c</span>[<span class=\"dc\">id</span>] ||= <span class=\"dc\">@svc</span>.<span class=\"fn\">get_data</span>(<span class=\"dc\">id</span>)\n  <span class=\"kw\">end</span>\n<span class=\"kw\">end</span>"}

